import os
import subprocess

def backup_directory(directory, format):
    """
    Creates a compressed archive of the given directory.

    Args:
        directory: The path to the directory to backup.
        format: The compression format (tar.gz, tar.bz2, zip, 7z).
    """

    # Create the archive file name.
    archive_file = f"{directory}.{format}"

    # Run the appropriate command based on the compression format.
    if format == "tar.gz":
        subprocess.run(["tar", "-cvpzf", archive_file, directory])
    elif format == "tar.bz2":
        subprocess.run(["tar", "-cvjbf", archive_file, directory])
    elif format == "zip":
        subprocess.run(["zip", archive_file, directory])
    elif format == "7z":
        subprocess.run(["7z", "a", archive_file, directory])
    else:
        raise ValueError(f"Unsupported compression format: {format}")

# Example usage.
backup_directory("/path/to/directory", "tar.gz")